// src/config.js
// ─────────────────────────────────────────────────────────────────────────────
// Single source of truth for the backend URL.
//
// HOW TO CHANGE FOR MOBILE / CLOUDFLARE TUNNEL:
//   Replace the BASE_URL value with your Cloudflare backend tunnel URL.
//   e.g. 'https://abc-def-ghi.trycloudflare.com'
//
// IMPORTANT: Change it here only — don't edit api.js, AuthContext.js, or
// Navbar.js individually.
// ─────────────────────────────────────────────────────────────────────────────

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

export default BASE_URL;
